import React, { useState } from 'react';

interface InputModalProps {
  title: string;
  label?: string;
  initialValue?: string;
  placeholder?: string;
  onConfirm: (value: string) => void;
  onCancel: () => void;
}

export const InputModal: React.FC<InputModalProps> = ({ title, label, initialValue = '', placeholder, onConfirm, onCancel }) => {
  const [value, setValue] = useState(initialValue);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (value.trim()) {
      onConfirm(value);
    }
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-75 z-[60] flex items-center justify-center p-4" onClick={onCancel}>
      <div className="bg-background-secondary rounded-lg shadow-xl w-full max-w-md flex flex-col border border-border-neutral" onClick={e => e.stopPropagation()}>
        <header className="p-4 border-b border-border-neutral">
          <h2 className="text-xl font-bold text-text-primary">{title}</h2>
        </header>
        <form onSubmit={handleSubmit} className="p-6">
            {label && <label className="block text-sm font-medium text-text-primary mb-2">{label}</label>}
            <input
                type="text"
                value={value}
                onChange={(e) => setValue(e.target.value)}
                placeholder={placeholder}
                className="w-full bg-background-primary border border-border-strong rounded-md shadow-sm py-2 px-3 text-text-primary focus:outline-none focus:ring-primary-500 focus:border-primary-500"
                autoFocus
            />
            <div className="mt-6 flex justify-end space-x-3">
                <button type="button" onClick={onCancel} className="py-2 px-4 rounded-md text-text-primary bg-background-tertiary hover:bg-opacity-80 transition-colors">Cancel</button>
                <button type="submit" disabled={!value.trim()} className="py-2 px-4 rounded-md text-text-accent bg-primary-600 hover:bg-primary-500 disabled:opacity-50 transition-colors">Confirm</button>
            </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Character, ChatSession, Message, CryptoKeys, GeminiApiRequest, Lorebook } from '../types.ts';
import { streamChatResponse, streamGenericResponse, generateContent } from '../services/geminiService.ts';
import * as cryptoService from '../services/cryptoService.ts';
import * as ttsService from '../services/ttsService.ts';
import * as ragService from '../services/ragService.ts';
import * as lorebookService from '../services/lorebookService.ts';
import { logger } from '../services/loggingService.ts';
import { ChatBubbleIcon } from './icons/ChatBubbleIcon.tsx';
import { ImageIcon } from './icons/ImageIcon.tsx';
import { BookIcon } from './icons/BookIcon.tsx';
import { BrainIcon } from './icons/BrainIcon.tsx';
import { SpeakerIcon } from './icons/SpeakerIcon.tsx';
import { MemoryImportModal } from './MemoryImportModal.tsx';
import { CheckCircleIcon } from './icons/CheckCircleIcon.tsx';
import { ExclamationTriangleIcon } from './icons/ExclamationTriangleIcon.tsx';
import { PluginSandbox } from '../services/pluginSandbox.ts';
import { ImageGenerationWindow } from './ImageGenerationWindow.tsx';
import { PaletteIcon } from './icons/PaletteIcon.tsx';
import { InputModal } from './InputModal.tsx';

interface ChatInterfaceProps {
  session: ChatSession;
  allCharacters: Character[];
  allChatSessions: ChatSession[];
  allLorebooks: Lorebook[];
  userKeys?: CryptoKeys;
  onSessionUpdate: (session: ChatSession) => void;
  onCharacterUpdate: (character: Character) => void;
  onTriggerHook: <T, R>(hookName: string, data: T) => Promise<R>;
  onMemoryImport: (fromSessionId: string, toSessionId: string) => void;
  onSaveBackup: () => void;
  handlePluginApiRequest: (request: GeminiApiRequest) => Promise<any>;
}

interface InputModalState {
    title: string;
    label: string;
    placeholder?: string;
    onConfirm: (value: string) => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
    session, 
    allCharacters, 
    allChatSessions,
    allLorebooks,
    userKeys, 
    onSessionUpdate, 
    onCharacterUpdate, 
    onTriggerHook,
    onMemoryImport,
    onSaveBackup,
    handlePluginApiRequest,
}) => {
  const [currentSession, setCurrentSession] = useState<ChatSession>(session);
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [autoConverseStatus, setAutoConverseStatus] = useState<'stopped' | 'running' | 'paused'>('stopped');
  const [isMemoryModalVisible, setIsMemoryModalVisible] = useState(false);
  const [isTtsEnabled, setIsTtsEnabled] = useState(false);
  const [verifiedSignatures, setVerifiedSignatures] = useState<Record<string, boolean>>({});
  const [isImageWindowVisible, setIsImageWindowVisible] = useState(false);
  const [inputModal, setInputModal] = useState<InputModalState | null>(null);

  const nextSpeakerIndex = useRef(0);
  const systemOverride = useRef<string | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const imageClickTimeout = useRef<number | null>(null);
  const narratorClickTimeout = useRef<number | null>(null);
  const autoConverseTimeout = useRef<number | null>(null);

  // Refs to avoid closure issues with state in timeouts/async calls
  const autoConverseStatusRef = useRef(autoConverseStatus);
  useEffect(() => {
    autoConverseStatusRef.current = autoConverseStatus;
  }, [autoConverseStatus]);

  const currentSessionRef = useRef(session);
  useEffect(() => {
    currentSessionRef.current = currentSession;
  }, [currentSession]);

  const participants = useMemo(() => {
    return allCharacters.filter(c => currentSession.characterIds.includes(c.id));
  }, [allCharacters, currentSession.characterIds]);

  const attachedLorebooks = useMemo(() => {
    return (currentSession.lorebookIds || []).map(id => allLorebooks.find(lb => lb.id === id)).filter(Boolean) as Lorebook[];
  }, [allLorebooks, currentSession.lorebookIds]);

  const avatarSizeClass = useMemo(() => {
    switch (currentSession.uiSettings?.avatarSize) {
      case 'small': return 'w-8 h-8';
      case 'large': return 'w-12 h-12';
      default: return 'w-10 h-10'; // Medium is default
    }
  }, [currentSession.uiSettings?.avatarSize]);

  useEffect(() => {
    if (session.id !== currentSessionRef.current.id) {
        setCurrentSession(session);
        if (autoConverseStatusRef.current !== 'stopped') {
            setAutoConverseStatus('stopped');
            if (autoConverseTimeout.current) clearTimeout(autoConverseTimeout.current);
        }
    }
  }, [session]);

  useEffect(() => {
    const verifyAllMessages = async () => {
        const verificationResults: Record<string, boolean> = {};
        for (const msg of currentSession.messages) {
            if (msg.signature && msg.publicKeyJwk) {
                try {
                    const publicKey = await cryptoService.importKey(msg.publicKeyJwk, 'verify');
                    const dataToVerify: Partial<Message> = { ...msg };
                    delete dataToVerify.signature;
                    delete dataToVerify.publicKeyJwk;
                    const canonicalString = cryptoService.createCanonicalString(dataToVerify);
                    verificationResults[msg.timestamp] = await cryptoService.verify(canonicalString, msg.signature, publicKey);
                } catch (e) {
                    logger.error("Message verification failed during check", e);
                    verificationResults[msg.timestamp] = false;
                }
            }
        }
        setVerifiedSignatures(verificationResults);
    };
    verifyAllMessages();
  }, [currentSession.messages]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [currentSession.messages, isStreaming]);

  useEffect(() => {
    return () => {
      if (autoConverseTimeout.current) clearTimeout(autoConverseTimeout.current);
      ttsService.cancel();
    }
  }, []);

  const updateSession = useCallback((updater: (session: ChatSession) => ChatSession) => {
    const newSession = updater(currentSessionRef.current);
    setCurrentSession(newSession);
    onSessionUpdate(newSession);
  }, [onSessionUpdate]);

  const addMessage = useCallback((message: Message) => {
    updateSession(prevSession => ({ ...prevSession, messages: [...prevSession.messages, message] }));
  }, [updateSession]);

  const addSystemMessage = useCallback((content: string) => {
    const systemMessage: Message = {
      role: 'narrator',
      content,
      timestamp: new Date().toISOString()
    };
    addMessage(systemMessage);
  }, [addMessage]);

  const triggerAIResponse = useCallback(async (character: Character, history: Message[], override?: string) => {
    if (history.filter(m => m.content).length === 0) {
      addSystemMessage("AI cannot respond to an empty history.");
      return;
    }

    let finalHistory = history;
    let finalOverride = override || '';

    // --- Lorebook Context Injection ---
    if (attachedLorebooks.length > 0) {
        const loreContext = lorebookService.findRelevantLore(history, attachedLorebooks);
        if (loreContext) {
            logger.log("Injecting Lorebook context for response.", { character: character.name });
            const contextInstruction = `[WORLD INFO]:\n${loreContext}`;
            finalOverride = `${contextInstruction}\n\n${finalOverride}`;
        }
    }

    if (character.pluginEnabled && character.pluginCode) {
        addSystemMessage(`Executing character logic for ${character.name}...`);
        try {
            const sandbox = new PluginSandbox(handlePluginApiRequest);
            await sandbox.loadCode(character.pluginCode);

            const hookPayload = { history, systemOverride: finalOverride };
            const modifiedPayload = await sandbox.executeHook<{history: Message[], systemOverride?: string}>('beforeResponseGenerate', hookPayload);

            finalHistory = modifiedPayload.history;
            finalOverride = modifiedPayload.systemOverride || '';

            sandbox.terminate();
            logger.log(`Character logic for "${character.name}" executed successfully.`);
        } catch (error) {
            logger.error(`Error executing character logic for "${character.name}":`, error);
            addSystemMessage(`Error in character logic for ${character.name}. See logs for details.`);
        }
    }


    setIsStreaming(true);
    const modelPlaceholder: Message = {
        role: 'model',
        content: '',
        timestamp: new Date().toISOString(),
        characterId: character.id
    };

    updateSession(current => ({ ...current, messages: [...finalHistory, modelPlaceholder] }));

    let fullResponse = '';

    try {
        await streamChatResponse(
            character,
            participants,
            finalHistory,
            (chunk) => {
                fullResponse += chunk;
                const messages = currentSessionRef.current.messages;
                const lastMessage = messages[messages.length - 1];
                if(lastMessage && lastMessage.timestamp === modelPlaceholder.timestamp) {
                    lastMessage.content = fullResponse;
                    const msgElement = document.getElementById(modelPlaceholder.timestamp);
                    if (msgElement) {
                       msgElement.innerHTML = fullResponse.replace(/\n/g, '<br>');
                    }
                }
            },
            finalOverride
        );
    } catch (error) {
        logger.error("Streaming failed:", error);
        fullResponse = "Sorry, an error occurred while responding.";
    } finally {
        setIsStreaming(false);

        const imageRegex = /\[generate_image:\s*(.*?)\]/g;
        const imageMatches = [...fullResponse.matchAll(imageRegex)];
        const cleanedResponse = fullResponse.replace(imageRegex, '').trim();

        if (cleanedResponse.length > 0 || imageMatches.length > 0) {
            let finalMessage: Message = { ...modelPlaceholder, content: cleanedResponse };

            if (character.keys) {
                try {
                    const privateKey = await cryptoService.importKey(character.keys.privateKey, 'sign');
                    finalMessage.publicKeyJwk = character.keys.publicKey;
                    const dataToSign: Partial<Message> = { ...finalMessage };
                    delete dataToSign.signature;
                    delete dataToSign.publicKeyJwk;
                    const canonicalString = cryptoService.createCanonicalString(dataToSign);
                    finalMessage.signature = await cryptoService.sign(canonicalString, privateKey);
                } catch (e) {
                    logger.error(`Failed to sign message for character ${character.name}`, e);
                }
            }

            if (isTtsEnabled && cleanedResponse) {
                ttsService.speak(cleanedResponse, character.voiceURI);
            }

            updateSession(current => {
                const updatedMessages = current.messages.map(msg =>
                    msg.timestamp === modelPlaceholder.timestamp ? finalMessage : msg
                );
                return { ...current, messages: updatedMessages };
            });

            for (const match of imageMatches) {
                const prompt = match[1];
                if (prompt) {
                    handleImageGeneration(prompt, 'direct');
                }
            }
        } else {
            updateSession(current => ({
                ...current,
                messages: current.messages.filter(m => m.timestamp !== modelPlaceholder.timestamp)
            }));
        }
    }
  }, [participants, isTtsEnabled, updateSession, addSystemMessage, handlePluginApiRequest, attachedLorebooks]);

  const continueAutoConversation = useCallback(async () => {
    if (autoConverseTimeout.current) clearTimeout(autoConverseTimeout.current);
    if (autoConverseStatusRef.current !== 'running' || participants.length < 2) {
        if (autoConverseStatusRef.current !== 'paused') {
            setAutoConverseStatus('stopped');
        }
        return;
    }

    const speaker = participants[nextSpeakerIndex.current % participants.length];
    nextSpeakerIndex.current += 1;
    const otherParticipantNames = participants.filter(p => p.id !== speaker.id).map(p => p.name).join(', ');
    const override = `You are in an automated conversation with ${otherParticipantNames}. Continue the conversation naturally based on the history. Your response should be directed at them, not a user. Do not act as a narrator.`;

    await triggerAIResponse(speaker, currentSessionRef.current.messages, override);

    if (autoConverseStatusRef.current === 'running') {
        autoConverseTimeout.current = window.setTimeout(() => continueAutoConversation(), 3000);
    }
  }, [participants, triggerAIResponse]);

  const startAutoConversation = useCallback(async (topic: string) => {
    const starterMessage: Message = {
        role: 'narrator',
        content: `[The AIs will now converse about: "${topic}"]`,
        timestamp: new Date().toISOString()
    };
    const updatedMessages = [...currentSessionRef.current.messages, starterMessage];
    updateSession(current => ({...current, messages: updatedMessages}));

    const firstSpeaker = participants[nextSpeakerIndex.current % participants.length];
    nextSpeakerIndex.current += 1;
    const otherParticipantNames = participants.filter(p => p.id !== firstSpeaker.id).map(p => p.name).join(', ');
    const override = `You are in an automated conversation with ${otherParticipantNames}. The user has set the topic: "${topic}". Start the conversation. Your response should be directed at them, not a user. Do not act as a narrator.`;

    await triggerAIResponse(firstSpeaker, updatedMessages, override);

    if (autoConverseStatusRef.current === 'running') {
        autoConverseTimeout.current = window.setTimeout(continueAutoConversation, 3000);
    }
  }, [participants, triggerAIResponse, updateSession, continueAutoConversation]);

  const handleCommand = async (command: string, args: string) => {
    setInput('');
    switch (command) {
        case 'image': {
            handleImageGeneration(args, 'direct');
            break;
        }
        case 'narrate': {
            handleNarration(args, 'direct');
            break;
        }
        case 'snapshot':
        case 'memorize': {
            const history = currentSessionRef.current.messages.slice(-10);
            if (history.length === 0) {
                addSystemMessage("Not enough conversation history to save a memory snapshot.");
                return;
            }
            addSystemMessage("Generating memory snapshot...");
            const context = history.map(m => `${m.role === 'model' ? allCharacters.find(c => c.id === m.characterId)?.name || 'AI' : 'User'}: ${m.content}`).join('\n');
            const prompt = `Summarize the key events, information, and character developments from this recent conversation snippet into a concise paragraph for a character's long-term memory. Focus on facts and relationship changes. Conversation:\n\n${context}`;

            try {
                const summary = await generateContent(prompt);
                participants.forEach(p => {
                    const updatedMemory = `${p.memory || ''}\n\n[Memory from ${new Date().toLocaleString()}]\n${summary}`;
                    onCharacterUpdate({...p, memory: updatedMemory.trim()});
                });
                addSystemMessage("Memory snapshot saved for all participants.");
            } catch (e) {
                logger.error("Failed to generate memory summary", e);
                addSystemMessage("Failed to generate memory summary. See logs for details.");
            }
            break;
        }
        case 'save': {
            addSystemMessage("Saving a full application backup... Your download will begin shortly.");
            onSaveBackup();
            break;
        }
        case 'sys': {
            systemOverride.current = args;
            addSystemMessage(`System override set for next AI response: "${args}"`);
            break;
        }
        case 'character': {
            const [charName, ...promptParts] = args.split(' ');
            const prompt = promptParts.join(' ');
            if (!charName || !prompt) {
                addSystemMessage("Usage: /character <name> <prompt>");
                return;
            }
            const target = participants.find(p => p.name.toLowerCase().startsWith(charName.toLowerCase()));
            if (!target) {
                addSystemMessage(`Character "${charName}" not found in this chat.`);
                return;
            }

            const targetIndex = participants.findIndex(p => p.id === target.id);
            nextSpeakerIndex.current = targetIndex;

            const userMessage = await createUserMessage(prompt);
            const newHistory = [...currentSessionRef.current.messages, userMessage];
            addMessage(userMessage);

            await triggerAIResponse(target, newHistory);
            break;
        }
        case 'converse': {
            if (autoConverseStatusRef.current !== 'stopped') {
                addSystemMessage("A conversation is already in progress. Use /end to stop it, or /pause to pause.");
                return;
            }
            if (participants.length > 1) {
                const topic = args || 'Anything at all.';
                setAutoConverseStatus('running');
                startAutoConversation(topic);
            } else {
                addSystemMessage("You need at least two characters in the chat to start a conversation.");
            }
            break;
        }
        case 'pause': {
            if (autoConverseStatusRef.current === 'running') {
                if (autoConverseTimeout.current) clearTimeout(autoConverseTimeout.current);
                setAutoConverseStatus('paused');
                addSystemMessage("AI conversation paused. Use /resume to continue.");
            } else if (autoConverseStatusRef.current === 'paused') {
                addSystemMessage("Conversation is already paused.");
            } else {
                 addSystemMessage("No conversation is running to pause.");
            }
            break;
        }
        case 'resume': {
             if (autoConverseStatusRef.current === 'paused') {
                setAutoConverseStatus('running');
                addSystemMessage("AI conversation resumed.");
                continueAutoConversation();
            } else if (autoConverseStatusRef.current === 'running') {
                addSystemMessage("Conversation is already running.");
            } else {
                addSystemMessage("No paused conversation to resume.");
            }
            break;
        }
        case 'quit':
        case 'end': {
            if (autoConverseStatusRef.current !== 'stopped') {
                if (autoConverseTimeout.current) clearTimeout(autoConverseTimeout.current);
                setAutoConverseStatus('stopped');
                addSystemMessage("AI conversation ended by user.");
            } else {
                addSystemMessage("No conversation is running to end.");
            }
            break;
        }
        default:
            addSystemMessage(`Unknown command: /${command}`);
    }
  };

  const createUserMessage = async (content: string): Promise<Message> => {
    let userMessage: Message = { role: 'user', content, timestamp: new Date().toISOString() };
    if (userKeys) {
        try {
            const privateKey = await cryptoService.importKey(userKeys.privateKey, 'sign');
            userMessage.publicKeyJwk = userKeys.publicKey;
            const dataToSign: Partial<Message> = { ...userMessage };
            delete dataToSign.signature;
            delete dataToSign.publicKeyJwk;
            const canonicalString = cryptoService.createCanonicalString(dataToSign);
            userMessage.signature = await cryptoService.sign(canonicalString, privateKey);
        } catch(e) {
            logger.error("Failed to sign user message", e);
        }
    }
    return userMessage;
  };

  const handleSendMessage = useCallback(async () => {
    const trimmedInput = input.trim();
    if (!trimmedInput) return;

    if (isStreaming && autoConverseStatusRef.current === 'stopped') return;

    if (autoConverseTimeout.current) clearTimeout(autoConverseTimeout.current);
    if (autoConverseStatusRef.current !== 'stopped') {
        setAutoConverseStatus('stopped');
        addSystemMessage("AI conversation stopped by user message.");
    }

    if (trimmedInput.startsWith('/')) {
        const [command, ...argsParts] = trimmedInput.substring(1).split(' ');
        const args = argsParts.join(' ');
        handleCommand(command.toLowerCase(), args);
        return;
    }

    const userMessage = await createUserMessage(trimmedInput);
    const newHistory = [...currentSessionRef.current.messages, userMessage];
    addMessage(userMessage);
    setInput('');

    if (participants.length > 0) {
        const respondent = participants[nextSpeakerIndex.current % participants.length];
        nextSpeakerIndex.current += 1;

        let finalSystemOverride = systemOverride.current;
        if (respondent.ragEnabled) {
            try {
                const ragContext = await ragService.findRelevantContext(trimmedInput, respondent);
                if (ragContext) {
                    logger.log("Injecting RAG context for response.", { character: respondent.name });
                    const contextInstruction = `[ADDITIONAL CONTEXT FROM KNOWLEDGE BASE]:\n${ragContext}`;
                    finalSystemOverride = finalSystemOverride
                        ? `${contextInstruction}\n\n${finalSystemOverride}`
                        : contextInstruction;
                }
            } catch (e) {
                logger.error("RAG context retrieval failed:", e);
                addSystemMessage(`Could not retrieve context for ${respondent.name}. Check embedding API settings.`);
            }
        }

        await triggerAIResponse(respondent, newHistory, finalSystemOverride || undefined);

        if (systemOverride.current) {
            systemOverride.current = null;
        }
    }

  }, [input, isStreaming, participants, addMessage, addSystemMessage, triggerAIResponse, userKeys, handleCommand]);

  const handleImageGeneration = async (prompt: string, type: 'direct' | 'summary') => {
      const attachmentMessage: Message = {
          role: 'narrator',
          content: `Generating image for prompt: "${type === 'summary' ? 'Summarizing context...' : prompt}"`,
          timestamp: new Date().toISOString(),
          attachment: { type: 'image', status: 'loading', prompt }
      };
      addMessage(attachmentMessage);

      try {
        const payload = type === 'summary'
            ? { type: 'summary', value: prompt }
            : { type: 'direct', value: prompt };

        // Use type assertion instead of explicit generic arguments to avoid parser issues
        const result = await onTriggerHook('generateImage', payload) as {url?: string, error?: string};

        if (result.url) {
            updateSession(curr => {
                const updatedMessages = curr.messages.map((m): Message => m.timestamp === attachmentMessage.timestamp 
                    ? { ...m, content: '', attachment: { ...m.attachment!, status: 'done', url: result.url } }
                    : m
                );
                return { ...curr, messages: updatedMessages };
            });
        } else {
            throw new Error(result.error || 'Image generation failed with no message.');
        }
      } catch (error) {
           const errorMessage = error instanceof Error ? error.message : String(error);
           logger.error('Image generation failed:', error);
           updateSession(curr => {
                const updatedMessages = curr.messages.map((m): Message => m.timestamp === attachmentMessage.timestamp 
                    ? { ...m, content: `Image generation failed: ${errorMessage}`, attachment: { ...m.attachment!, status: 'error' } }
                    : m
                );
                return { ...curr, messages: updatedMessages };
            });
      }
  };

  const handleGenerateImageInWindow = useCallback(async (prompt: string) => {
    logger.log("Generating image in floating window for prompt:", prompt);
    const payload = { type: 'direct', value: prompt };
    // Use type assertion instead of explicit generic arguments to avoid parser issues
    const result = await onTriggerHook('generateImage', payload) as {url?: string, error?: string};
    return result;
  }, [onTriggerHook]);

  const handleNarration = async (prompt: string, type: 'direct' | 'summary') => {
    let finalPrompt = prompt;
    if (type === 'summary') {
        const summaryPrompt = `Based on the following conversation, create a short, descriptive narration of the current scene or situation. Be creative and concise. Conversation:\n\n${prompt}`;
        try {
            finalPrompt = await generateContent(summaryPrompt);
        } catch(e) {
            addSystemMessage("Failed to summarize context for narration.");
            return;
        }
    }

    const narratorPlaceholder: Message = { role: 'narrator', content: '', timestamp: new Date().toISOString() };
    addMessage(narratorPlaceholder);

    let fullResponse = '';
    await streamGenericResponse(
        "You are a neutral, third-person narrator for a story. Describe the scene or events based on the user's request.",
        finalPrompt,
        (chunk) => {
            fullResponse += chunk;
            const msgElement = document.getElementById(narratorPlaceholder.timestamp);
            if (msgElement) {
                msgElement.innerHTML = fullResponse.replace(/\n/g, '<br>');
            }
        }
    );
     updateSession(curr => {
        const finalMessages = curr.messages.map(m => m.timestamp === narratorPlaceholder.timestamp ? {...m, content: fullResponse} : m);
        return { ...curr, messages: finalMessages };
    });
  };

  const handleImageButtonClick = () => {
    if (imageClickTimeout.current) {
      clearTimeout(imageClickTimeout.current);
      imageClickTimeout.current = null;
      const context = currentSessionRef.current.messages.slice(-5).map(m => `${m.role}: ${m.content}`).join('\n');
      handleImageGeneration(context, 'summary');
    } else {
      imageClickTimeout.current = window.setTimeout(() => {
        setInputModal({
            title: "Generate Image",
            label: "Enter a prompt for the image:",
            placeholder: "A cyberpunk city in the rain...",
            onConfirm: (prompt) => {
                handleImageGeneration(prompt, 'direct');
                setInputModal(null);
            }
        });
        imageClickTimeout.current = null;
      }, 250);
    }
  };

  const handleNarratorButtonClick = () => {
    if (narratorClickTimeout.current) {
      clearTimeout(narratorClickTimeout.current);
      narratorClickTimeout.current = null;
      const context = currentSessionRef.current.messages.slice(-5).map(m => `${m.role}: ${m.content}`).join('\n');
      handleNarration(context, 'summary');
    } else {
      narratorClickTimeout.current = window.setTimeout(() => {
        setInputModal({
            title: "Narrator Instruction",
            label: "Enter a narration instruction:",
            placeholder: "Describe the weather changing unexpectedly...",
            onConfirm: (prompt) => {
                handleNarration(prompt, 'direct');
                setInputModal(null);
            }
        });
        narratorClickTimeout.current = null;
      }, 250);
    }
  };

  const renderMessageContent = (message: Message) => {
    if (message.attachment?.type === 'image') {
        switch(message.attachment.status) {
            case 'loading': return <div className="p-4 text-center">Generating image...</div>;
            case 'done': return <img src={message.attachment.url} alt={message.attachment.prompt || 'Generated Image'} className="rounded-lg max-w-sm" />;
            case 'error': return null;
        }
    }
    return <span id={message.timestamp} dangerouslySetInnerHTML={{ __html: message.content.replace(/\n/g, '<br />') }} />;
  };

  const getCharacterById = (id: string) => allCharacters.find(c => c.id === id);

  const isInputDisabled = isStreaming && autoConverseStatus === 'stopped';

  return (
    <div className="flex flex-col h-full bg-background-primary">
      {isImageWindowVisible && (
        <ImageGenerationWindow 
            onGenerate={handleGenerateImageInWindow}
            onClose={() => setIsImageWindowVisible(false)}
        />
      )}
      {isMemoryModalVisible && (
        <MemoryImportModal 
            allSessions={allChatSessions}
            currentSessionId={currentSession.id}
            onClose={() => setIsMemoryModalVisible(false)}
            onImport={(fromSessionId) => {
                onMemoryImport(fromSessionId, currentSession.id);
                setIsMemoryModalVisible(false);
            }}
        />
      )}
      {inputModal && (
        <InputModal 
            title={inputModal.title}
            label={inputModal.label}
            placeholder={inputModal.placeholder}
            onConfirm={inputModal.onConfirm}
            onCancel={() => setInputModal(null)}
        />
      )}
      <header className="flex items-center p-3 border-b border-border-neutral">
        <div className="flex -space-x-4">
            {participants.slice(0, 3).map(p => (
                <img key={p.id} src={p.avatarUrl || `https://picsum.photos/seed/${p.id}/40/40`} alt={p.name} className="w-10 h-10 rounded-full border-2 border-background-primary"/>
            ))}
        </div>
        <div className="ml-4 flex-1 min-w-0">
          <h2 className="text-lg font-bold text-text-primary truncate">{session.name}</h2>
          <p className="text-sm text-text-secondary truncate">{participants.map(p=>p.name).join(', ')}</p>
        </div>
      </header>

      <div className="flex-1 p-4 overflow-y-auto space-y-4">
        {currentSession.messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-text-secondary">
            <ChatBubbleIcon className="w-16 h-16 mb-4" />
            <p>No messages yet. Start the conversation!</p>
          </div>
        ) : (
          currentSession.messages.map((msg, index) => {
            if (msg.role === 'narrator') {
              return (
                <div key={index} className="text-center my-2 group relative">
                  <p id={msg.timestamp} className="text-sm text-text-secondary italic px-4">{renderMessageContent(msg)}</p>
                  <div className="absolute top-1/2 -translate-y-1/2 right-0 flex items-center opacity-0 group-hover:opacity-100 transition-opacity">
                     <button onClick={() => ttsService.speak(msg.content)} title="Read Aloud" className="p-1 rounded-full text-text-secondary hover:bg-background-tertiary">
                        <SpeakerIcon className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              );
            }
            const msgCharacter = msg.characterId ? getCharacterById(msg.characterId) : null;
            const isUser = msg.role === 'user';
            const characterVoiceURI = msg.role === 'model' && msgCharacter ? msgCharacter.voiceURI : undefined;
            return (
              <div key={index} className={`flex items-start gap-3 group ${isUser ? 'justify-end' : 'justify-start'}`}>
                {msg.role === 'model' && msgCharacter && (
                  <img src={msgCharacter.avatarUrl || `https://picsum.photos/seed/${msgCharacter.id}/40/40`} alt={msgCharacter.name} className={`${avatarSizeClass} rounded-full flex-shrink-0`} title={msgCharacter.name}/>
                )}
                <div className={`relative max-w-xl p-3 rounded-lg ${
                    isUser
                      ? 'bg-primary-600 text-text-accent'
                      : 'bg-background-secondary text-text-primary'
                  }`}>
                  <div className="absolute top-0 -translate-y-1/2 flex items-center opacity-0 group-hover:opacity-100 transition-opacity" style={isUser ? {left: '-2rem'} : {right: '-2rem'}}>
                     <button onClick={() => ttsService.speak(msg.content, characterVoiceURI)} title="Read Aloud" className="p-1 rounded-full text-text-secondary bg-background-tertiary hover:bg-opacity-80">
                        <SpeakerIcon className="w-4 h-4" />
                    </button>
                  </div>
                  {msg.role === 'model' && msgCharacter && <p className="font-bold text-sm mb-1">{msgCharacter.name}</p>}
                  {renderMessageContent(msg)}
                  {msg.signature && (
                    <div className="absolute -bottom-2 -right-2 bg-background-primary rounded-full p-0.5">
                        {verifiedSignatures[msg.timestamp] === true && <CheckCircleIcon className="w-4 h-4 text-accent-green" title="Signature Verified" />}
                        {verifiedSignatures[msg.timestamp] === false && <ExclamationTriangleIcon className="w-4 h-4 text-accent-yellow" title="Signature Invalid" />}
                    </div>
                  )}
                </div>
              </div>
            );
          })
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 border-t border-border-neutral">
        <div className="flex items-center bg-background-secondary rounded-lg p-2">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSendMessage(); } }}
            placeholder={
                autoConverseStatus === 'running' ? "AI conversation in progress... (/pause or /end)" :
                autoConverseStatus === 'paused' ? "AI conversation paused. (/resume or /end)" :
                `Message ${session.name}... (/converse)`
            }
            className="flex-1 bg-transparent resize-none focus:outline-none px-2 text-text-primary"
            rows={1}
            disabled={isInputDisabled}
          />
          <button 
                onClick={() => setIsImageWindowVisible(!isImageWindowVisible)} 
                title="Open Image Generation Window" 
                className={`p-2 rounded-full transition-colors ${isImageWindowVisible ? 'text-primary-500' : 'text-text-secondary hover:text-primary-500'}`} disabled={isInputDisabled}
            >
                <PaletteIcon className="w-6 h-6" />
            </button>
            <button 
                onClick={() => setIsTtsEnabled(!isTtsEnabled)} 
                title={isTtsEnabled ? "Disable Auto-TTS" : "Enable Auto-TTS for AI Responses"} 
                className={`p-2 rounded-full transition-colors ${isTtsEnabled ? 'text-primary-500' : 'text-text-secondary hover:text-primary-500'}`} disabled={isInputDisabled}
            >
                <SpeakerIcon className="w-6 h-6" />
            </button>
          <button onClick={() => setIsMemoryModalVisible(true)} title="Import Memory From Another Chat" className="p-2 text-text-secondary hover:text-primary-500 disabled:opacity-50" disabled={isInputDisabled}>
            <BrainIcon className="w-6 h-6" />
          </button>
          <button onClick={handleNarratorButtonClick} title="Narrate (Single-click for prompt, double-click for auto)" className="p-2 text-text-secondary hover:text-primary-500 disabled:opacity-50" disabled={isInputDisabled}>
            <BookIcon className="w-6 h-6" />
          </button>
          <button onClick={handleImageButtonClick} title="Generate Image (Single-click for prompt, double-click for auto)" className="p-2 text-text-secondary hover:text-primary-500 disabled:opacity-50" disabled={isInputDisabled}>
            <ImageIcon className="w-6 h-6" />
          </button>
          <button onClick={handleSendMessage} disabled={!input.trim() || isInputDisabled} className="p-2 text-text-secondary hover:text-primary-500 disabled:opacity-50" title="Send message">
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-6 h-6"><path d="M3.478 2.405a.75.75 0 00-.926.94l2.432 7.905H13.5a.75.75 0 010 1.5H4.984l-2.432 7.905a.75.75 0 00.926.94 60.519 60.519 0 0018.445-8.986.75.75 0 000-1.218A60.517 60.517 0 003.478 2.405z" /></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { UISettings, ChatSession, Character } from '../types';
import { generateContent } from '../services/geminiService';
import { logger } from '../services/loggingService';
import { SpinnerIcon } from './icons/SpinnerIcon.tsx';
import { UploadIcon } from './icons/UploadIcon.tsx';
import { SparklesIcon } from './icons/SparklesIcon.tsx';
import { TrashIcon } from './icons/TrashIcon.tsx';
import * as themeService from '../services/themeService.ts';
import { InputModal } from './InputModal.tsx';

interface AppearanceModalProps {
  settings: UISettings;
  currentChat: ChatSession | undefined;
  allCharacters: Character[];
  onUpdate: (settings: UISettings) => void;
  onGenerateImage: (prompt: string) => Promise<string | null>;
  onClose: () => void;
}

const ImageControl: React.FC<{
  label: string;
  imageUrl?: string;
  onUpload: (file: File) => void;
  onGenerate: (type: 'prompt' | 'auto' | 'character') => void;
  onClear: () => void;
  isGenerating: boolean;
  canAutoGenerate: boolean;
  canCharacterGenerate: boolean;
}> = ({ label, imageUrl, onUpload, onGenerate, onClear, isGenerating, canAutoGenerate, canCharacterGenerate }) => {
  const fileInputRef = React.useRef<HTMLInputElement>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 4 * 1024 * 1024) { // 4MB limit
      alert("File is too large. Please select an image under 4MB.");
      return;
    }
    onUpload(file);
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  return (
    <div className="space-y-3">
      <h3 className="text-lg font-medium text-text-primary">{label}</h3>
      <div className="h-40 w-full rounded-md border-2 border-dashed border-border-strong flex items-center justify-center bg-cover bg-center" style={{ backgroundImage: `url(${imageUrl || ''})`, backgroundColor: imageUrl ? '' : 'rgba(0,0,0,0.1)' }}>
        {!imageUrl && <span className="text-text-secondary">No Image Set</span>}
      </div>
      <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
        <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/png, image/jpeg, image/webp, image/gif" className="hidden" />
        <button onClick={() => fileInputRef.current?.click()} className="flex items-center justify-center space-x-2 px-3 py-2 text-sm font-medium text-center rounded-md bg-background-tertiary hover:bg-opacity-80 transition-colors">
            <UploadIcon className="w-4 h-4" /> <span>Upload</span>
        </button>
        <button onClick={() => onGenerate('prompt')} disabled={isGenerating} className="flex items-center justify-center space-x-2 px-3 py-2 text-sm font-medium text-center rounded-md bg-background-tertiary hover:bg-opacity-80 transition-colors disabled:opacity-50">
            {isGenerating ? <SpinnerIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />} <span>From Prompt</span>
        </button>
        <button onClick={() => onGenerate('auto')} disabled={isGenerating || !canAutoGenerate} className="flex items-center justify-center space-x-2 px-3 py-2 text-sm font-medium text-center rounded-md bg-background-tertiary hover:bg-opacity-80 transition-colors disabled:opacity-50" title={!canAutoGenerate ? "Not enough chat history available" : "Generate from chat context"}>
            {isGenerating ? <SpinnerIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />} <span>From Chat</span>
        </button>
        <button onClick={() => onGenerate('character')} disabled={isGenerating || !canCharacterGenerate} className="flex items-center justify-center space-x-2 px-3 py-2 text-sm font-medium text-center rounded-md bg-background-tertiary hover:bg-opacity-80 transition-colors disabled:opacity-50" title={!canCharacterGenerate ? "No characters in this chat" : "Generate from character details"}>
            {isGenerating ? <SpinnerIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />} <span>From Character</span>
        </button>
        <button onClick={onClear} className="col-span-2 md:col-span-1 flex items-center justify-center space-x-2 px-3 py-2 text-sm font-medium text-center rounded-md bg-accent-red/20 text-accent-red hover:bg-accent-red/30 transition-colors">
            <TrashIcon className="w-4 h-4" /> <span>Clear</span>
        </button>
      </div>
    </div>
  );
};

export const AppearanceModal: React.FC<AppearanceModalProps> = ({ settings, currentChat, allCharacters, onUpdate, onGenerateImage, onClose }) => {
  const [isGeneratingBg, setIsGeneratingBg] = useState(false);
  const [isGeneratingBanner, setIsGeneratingBanner] = useState(false);
  const [activeTheme, setActiveTheme] = useState(themeService.getTheme());
  const [inputModal, setInputModal] = useState<{ title: string, label: string, onConfirm: (val: string) => void } | null>(null);

  useEffect(() => {
    const unsubscribe = themeService.subscribe(() => {
      setActiveTheme(themeService.getTheme());
    });
    return unsubscribe;
  }, []);

  const participants = useMemo(() => {
    if (!currentChat) return [];
    return allCharacters.filter(c => currentChat.characterIds.includes(c.id));
  }, [allCharacters, currentChat]);

  const canAutoGenerate = !!currentChat && currentChat.messages.length >= 2;
  const canCharacterGenerate = participants.length > 0;

  const handleFileUpload = (file: File, type: 'background' | 'banner') => {
    const reader = new FileReader();
    reader.onload = () => {
      const newSettings = { ...settings };
      if (type === 'background') newSettings.backgroundImage = reader.result as string;
      if (type === 'banner') newSettings.bannerImage = reader.result as string;
      onUpdate(newSettings);
    };
    reader.readAsDataURL(file);
  };

  const handleGenerate = async (type: 'background' | 'banner', mode: 'prompt' | 'auto' | 'character') => {
    const setIsGenerating = type === 'background' ? setIsGeneratingBg : setIsGeneratingBanner;

    if (mode === 'prompt') {
        setInputModal({
            title: `Generate ${type === 'background' ? 'Background' : 'Banner'}`,
            label: "Enter an image prompt:",
            onConfirm: async (prompt) => {
                setInputModal(null);
                setIsGenerating(true);
                try {
                    const imageUrl = await onGenerateImage(prompt);
                    if (imageUrl) {
                        const newSettings = { ...settings };
                        if (type === 'background') newSettings.backgroundImage = imageUrl;
                        if (type === 'banner') newSettings.bannerImage = imageUrl;
                        onUpdate(newSettings);
                    }
                } catch (err) {
                    logger.error("Failed to generate image", err);
                    alert(`Could not generate image: ${err instanceof Error ? err.message : String(err)}`);
                } finally {
                    setIsGenerating(false);
                }
            }
        });
        return;
    }

    setIsGenerating(true);
    let promptText: string | null = null;

    try {
        if (mode === 'auto') {
            if (!canAutoGenerate) throw new Error("Not enough chat history to auto-generate an image.");
            const context = currentChat.messages.slice(-5).map(m => m.content).join('\n');
            const summaryPrompt = `Based on the following conversation, create a short, visually descriptive prompt for an atmospheric ${type} image. The prompt should capture the essence of the scene. Be creative and concise. Conversation:\n\n${context}`;
            promptText = await generateContent(summaryPrompt);
            logger.log(`Auto-generated image prompt from chat:`, promptText);
        } else if (mode === 'character') {
            if (!canCharacterGenerate) throw new Error("No characters in this chat to generate an image from.");
            const characterDetails = participants.map(p => {
                let details = `Name: ${p.name}\nDescription: ${p.description}\nPhysical Appearance: ${p.physicalAppearance}\nPersonality: ${p.personalityTraits}`;
                if (p.memory && p.memory !== 'No memories yet.') {
                    details += `\nRecent Memory: ${p.memory}`;
                }
                return details;
            }).join('\n\n---\n\n');

            const summaryPrompt = `Based on the following character details, create a short, visually descriptive prompt for an atmospheric ${type} image that represents them or their environment. Be creative and concise. Character Details:\n\n${characterDetails}`;
            promptText = await generateContent(summaryPrompt);
            logger.log(`Auto-generated image prompt from character details:`, promptText);
        }

        if (promptText) {
            const imageUrl = await onGenerateImage(promptText);
            if (imageUrl) {
                const newSettings = { ...settings };
                if (type === 'background') newSettings.backgroundImage = imageUrl;
                if (type === 'banner') newSettings.bannerImage = imageUrl;
                onUpdate(newSettings);
            }
        }
    } catch (err) {
        const message = err instanceof Error ? err.message : "An unknown error occurred.";
        logger.error("Failed to generate image prompt or image", err);
        alert(`Could not generate image: ${message}`);
    } finally {
        setIsGenerating(false);
    }
  };

  const handleClear = (type: 'background' | 'banner') => {
    const newSettings = { ...settings };
    if (type === 'background') newSettings.backgroundImage = undefined;
    if (type === 'banner') newSettings.bannerImage = undefined;
    onUpdate(newSettings);
  };

  const handleAvatarSizeChange = (size: 'small' | 'medium' | 'large') => {
    onUpdate({ ...settings, avatarSize: size });
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-75 z-40 flex items-center justify-center p-4" onClick={onClose}>
      <div className="bg-background-secondary rounded-lg shadow-xl w-full max-w-2xl flex flex-col" onClick={e => e.stopPropagation()}>
        <header className="p-4 border-b border-border-neutral flex justify-between items-center flex-shrink-0">
          <h2 className="text-xl font-bold text-text-primary">Appearance Settings</h2>
          <button onClick={onClose} className="text-text-secondary hover:text-text-primary transition-colors text-2xl font-bold leading-none p-1">&times;</button>
        </header>

        <div className="p-6 space-y-6 overflow-y-auto max-h-[70vh]">
          <div className="space-y-3">
            <h3 className="text-lg font-medium text-text-primary">Theme</h3>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {themeService.themes.map(theme => (
                <div key={theme.id} onClick={() => themeService.setTheme(theme.id)} className="cursor-pointer">
                  <div className={`h-16 w-full rounded-md border-2 flex items-end p-2 theme-preview theme-${theme.id} ${activeTheme === theme.id ? 'border-primary-500' : 'border-border-neutral'}`}>
                    <div className="w-4 h-4 rounded-full bg-primary-500"></div>
                  </div>
                  <p className={`text-center mt-2 text-sm ${activeTheme === theme.id ? 'text-primary-500 font-bold' : 'text-text-primary'}`}>{theme.name}</p>
                </div>
              ))}
            </div>
          </div>

          <ImageControl 
            label="Background Image"
            imageUrl={settings.backgroundImage}
            onUpload={(file) => handleFileUpload(file, 'background')}
            onGenerate={(mode) => handleGenerate('background', mode)}
            onClear={() => handleClear('background')}
            isGenerating={isGeneratingBg}
            canAutoGenerate={canAutoGenerate}
            canCharacterGenerate={canCharacterGenerate}
          />
          <ImageControl 
            label="Banner Image"
            imageUrl={settings.bannerImage}
            onUpload={(file) => handleFileUpload(file, 'banner')}
            onGenerate={(mode) => handleGenerate('banner', mode)}
            onClear={() => handleClear('banner')}
            isGenerating={isGeneratingBanner}
            canAutoGenerate={canAutoGenerate}
            canCharacterGenerate={canCharacterGenerate}
          />

          <div className="space-y-3 pt-6 border-t border-border-neutral">
            <h3 className="text-lg font-medium text-text-primary">Avatar Size</h3>
            <p className="text-sm text-text-secondary">Controls the size of character avatars displayed next to messages in this chat.</p>
            <div className="flex items-center space-x-4">
                {(['small', 'medium', 'large'] as const).map(size => (
                    <label key={size} className="flex items-center space-x-2 cursor-pointer">
                        <input
                            type="radio"
                            name="avatar-size"
                            value={size}
                            checked={(settings.avatarSize || 'medium') === size}
                            onChange={() => handleAvatarSizeChange(size)}
                            className="h-4 w-4 text-primary-600 border-border-strong bg-background-primary focus:ring-primary-500"
                        />
                        <span className="capitalize text-text-primary">{size}</span>
                    </label>
                ))}
            </div>
          </div>

        </div>

        <footer className="p-4 border-t border-border-neutral flex justify-end">
            <button onClick={onClose} className="py-2 px-4 rounded-md text-text-primary bg-background-tertiary hover:bg-opacity-80">Close</button>
        </footer>
      </div>
      {inputModal && (
        <InputModal 
            title={inputModal.title}
            label={inputModal.label}
            onConfirm={inputModal.onConfirm}
            onCancel={() => setInputModal(null)}
        />
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { VaultItem } from '../types';
import { saveVaultItem, getVaultItems, deleteVaultItem, encryptPackage, decryptPackage } from '../services/secureStorage';
import { logger } from '../services/loggingService';
import { VaultIcon } from './icons/VaultIcon';
import { FolderIcon } from './icons/FolderIcon';
import { DownloadIcon } from './icons/DownloadIcon';
import { TrashIcon } from './icons/TrashIcon';
import { PlusIcon } from './icons/PlusIcon';
import { UploadIcon } from './icons/UploadIcon';
import { LockOpenIcon } from './icons/LockOpenIcon';
import { LockIcon } from './icons/LockIcon';
import { InputModal } from './InputModal.tsx';

interface VaultProps {
    onClose: () => void;
}

const ROOT_ID = 'root';
const SHARED_ID = 'not-mine';

export const Vault: React.FC<VaultProps> = ({ onClose }) => {
    const [currentFolderId, setCurrentFolderId] = useState<string>(ROOT_ID);
    const [items, setItems] = useState<VaultItem[]>([]);
    const [loading, setLoading] = useState(false);
    const [selectedItem, setSelectedItem] = useState<VaultItem | null>(null);
    const [sharePassword, setSharePassword] = useState('');
    const [importPassword, setImportPassword] = useState('');
    const [showShareModal, setShowShareModal] = useState(false);
    const [showImportModal, setShowImportModal] = useState(false);
    const [inputModal, setInputModal] = useState<{ title: string, label: string, onConfirm: (val: string) => void } | null>(null);

    const fileInputRef = useRef<HTMLInputElement>(null);
    const secureImportInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        loadItems(currentFolderId);
    }, [currentFolderId]);

    const loadItems = async (folderId: string) => {
        setLoading(true);
        try {
            const vaultItems = await getVaultItems(folderId);
            // Sort: Folders first, then files
            const sorted = vaultItems.sort((a, b) => {
                if (a.type === b.type) return a.name.localeCompare(b.name);
                return a.type === 'folder' ? -1 : 1;
            });
            setItems(sorted);
        } catch (error) {
            logger.error("Failed to load vault items", error);
        } finally {
            setLoading(false);
        }
    };

    const handleCreateFolder = () => {
        setInputModal({
            title: "Create New Folder",
            label: "Folder Name:",
            onConfirm: async (name) => {
                const newFolder: VaultItem = {
                    id: crypto.randomUUID(),
                    parentId: currentFolderId,
                    name,
                    type: 'folder',
                    createdAt: new Date().toISOString()
                };
                await saveVaultItem(newFolder);
                loadItems(currentFolderId);
                setInputModal(null);
            }
        });
    };

    const handleUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = async (event) => {
            const content = event.target?.result as string;
            const newItem: VaultItem = {
                id: crypto.randomUUID(),
                parentId: currentFolderId,
                name: file.name,
                type: 'file',
                mimeType: file.type,
                content: content, // This gets encrypted by saveVaultItem
                size: file.size,
                createdAt: new Date().toISOString()
            };

            setLoading(true);
            await saveVaultItem(newItem);
            loadItems(currentFolderId);
            setLoading(false);
        };
        reader.readAsDataURL(file);
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure? This cannot be undone.")) return;
        await deleteVaultItem(id);
        // If it's a folder, we strictly should delete children too, 
        // but for this MVP we just delete the entry. Children become orphans (hidden).
        // A robust implementation would recursively delete.
        loadItems(currentFolderId);
        setSelectedItem(null);
    };

    const handleSecureShare = async () => {
        if (!selectedItem || !sharePassword) return;
        if (selectedItem.type === 'folder') {
            alert("Folder sharing not supported in this version. Please zip it or share files individually.");
            return;
        }

        try {
            // Decrypt content (it's loaded decrypted from getVaultItems), then encrypt with share password
            // Note: In getVaultItems, content is already decrypted for us.
            const encryptedPackage = await encryptPackage(JSON.stringify(selectedItem), sharePassword);

            const blob = new Blob([encryptedPackage], { type: 'application/octet-stream' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${selectedItem.name}.nexusvault`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);

            setShowShareModal(false);
            setSharePassword('');
            alert("Secure package generated!");
        } catch (e) {
            logger.error("Sharing failed", e);
            alert("Encryption failed.");
        }
    };

    const handleSecureImport = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        // We need the password first
        if (!importPassword) {
            alert("Please set the decryption password first.");
            return;
        }

        const reader = new FileReader();
        reader.onload = async (event) => {
            try {
                const encryptedContent = event.target?.result as string;
                // Decrypt
                const decryptedJson = await decryptPackage(encryptedContent, importPassword);
                const importedItem = JSON.parse(decryptedJson) as VaultItem;

                // Force into "Not Mine" folder or current folder?
                // Request said "import others work into the not mine folder"
                // Let's create the folder if it doesn't exist

                // Check if 'not-mine' folder exists, if not create it
                // Actually, 'not-mine' is just an ID concept here.

                importedItem.id = crypto.randomUUID(); // New ID to avoid conflicts
                importedItem.parentId = SHARED_ID; // Force location
                importedItem.name = `[Imported] ${importedItem.name}`;
                importedItem.createdAt = new Date().toISOString();

                // Ensure Not Mine folder exists
                const notMineFolder: VaultItem = {
                    id: SHARED_ID,
                    parentId: ROOT_ID,
                    name: 'Not Mine (Incoming)',
                    type: 'folder',
                    createdAt: new Date().toISOString()
                };
                // Try to save folder (idempotent overwrite is fine)
                await saveVaultItem(notMineFolder);
                await saveVaultItem(importedItem);

                alert("File imported successfully into 'Not Mine' folder.");

                if (currentFolderId === SHARED_ID) {
                    loadItems(SHARED_ID);
                } else {
                    setCurrentFolderId(SHARED_ID);
                }
                setShowImportModal(false);
                setImportPassword('');

            } catch (error) {
                logger.error("Import failed", error);
                alert("Import failed. Incorrect password or invalid file.");
            }
        };
        // The encrypted package is JSON string, but FileReader reads as text usually. 
        // encryptPackage returns string.
        reader.readAsText(file);
        if (secureImportInputRef.current) secureImportInputRef.current.value = '';
    };

    const downloadFile = (item: VaultItem) => {
        if (!item.content) return;
        const a = document.createElement('a');
        a.href = item.content;
        a.download = item.name;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
    };

    const formatSize = (bytes?: number) => {
        if (!bytes) return '0 B';
        if (bytes < 1024) return bytes + ' B';
        if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
        return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
    };

    return (
        <div className="fixed inset-0 bg-black/90 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
            <div className="bg-gray-900 border border-green-500/30 rounded-lg shadow-2xl w-full max-w-6xl h-[85vh] flex flex-col overflow-hidden font-mono text-green-400">
                {/* Header */}
                <header className="p-4 border-b border-green-500/30 flex justify-between items-center bg-gray-900/50">
                    <div className="flex items-center space-x-3">
                        <VaultIcon className="w-8 h-8 text-green-500" />
                        <h1 className="text-2xl font-bold tracking-widest uppercase">Nexus Secure Vault</h1>
                    </div>
                    <button onClick={onClose} className="text-green-500 hover:text-green-300 text-2xl font-bold">&times;</button>
                </header>

                {/* Toolbar */}
                <div className="p-2 border-b border-green-500/30 flex items-center space-x-2 bg-gray-800/50">
                    {currentFolderId !== ROOT_ID && (
                        <button onClick={() => setCurrentFolderId(ROOT_ID)} className="px-3 py-1 bg-gray-800 hover:bg-gray-700 rounded border border-green-500/30 text-sm">
                            &larr; Root
                        </button>
                    )}
                    <button onClick={handleCreateFolder} className="flex items-center space-x-1 px-3 py-1 bg-gray-800 hover:bg-gray-700 rounded border border-green-500/30 text-sm">
                        <PlusIcon className="w-4 h-4" /> <span>New Folder</span>
                    </button>
                    <input type="file" ref={fileInputRef} onChange={handleUpload} className="hidden" />
                    <button onClick={() => fileInputRef.current?.click()} className="flex items-center space-x-1 px-3 py-1 bg-gray-800 hover:bg-gray-700 rounded border border-green-500/30 text-sm">
                        <UploadIcon className="w-4 h-4" /> <span>Upload File</span>
                    </button>
                    <div className="flex-1"></div>
                    <button onClick={() => setShowImportModal(true)} className="flex items-center space-x-1 px-3 py-1 bg-green-900/30 hover:bg-green-900/50 rounded border border-green-500 text-sm text-green-300">
                        <DownloadIcon className="w-4 h-4" /> <span>Import Secure Pkg</span>
                    </button>
                </div>

                <div className="flex flex-1 overflow-hidden">
                    {/* Sidebar / Quick Access */}
                    <div className="w-48 border-r border-green-500/30 p-4 space-y-2 bg-black/20">
                        <h3 className="text-xs uppercase text-green-600 font-bold mb-2">Locations</h3>
                        <div 
                            onClick={() => setCurrentFolderId(ROOT_ID)}
                            className={`cursor-pointer p-2 rounded ${currentFolderId === ROOT_ID ? 'bg-green-500/20 text-white' : 'hover:bg-green-500/10'}`}
                        >
                            My Files
                        </div>
                        <div 
                            onClick={() => setCurrentFolderId(SHARED_ID)}
                            className={`cursor-pointer p-2 rounded ${currentFolderId === SHARED_ID ? 'bg-green-500/20 text-white' : 'hover:bg-green-500/10'}`}
                        >
                            Not Mine (Incoming)
                        </div>
                    </div>

                    {/* Main Content */}
                    <div className="flex-1 p-4 overflow-y-auto">
                        {loading ? (
                            <div className="text-center mt-10 animate-pulse">Accessing Secure Storage...</div>
                        ) : items.length === 0 ? (
                            <div className="text-center mt-10 text-green-700">Vault Empty.</div>
                        ) : (
                            <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
                                {items.map(item => (
                                    <div 
                                        key={item.id}
                                        onClick={() => item.type === 'folder' ? setCurrentFolderId(item.id) : setSelectedItem(item)}
                                        className={`group relative p-4 rounded border ${selectedItem?.id === item.id ? 'border-green-400 bg-green-500/10' : 'border-green-500/20 bg-gray-800/30 hover:border-green-500/50'} flex flex-col items-center justify-center cursor-pointer transition-all`}
                                    >
                                        {item.type === 'folder' ? (
                                            <FolderIcon className="w-12 h-12 text-yellow-500/80 mb-2" />
                                        ) : (
                                            <div className="relative">
                                                {item.mimeType?.startsWith('image/') ? (
                                                    <img src={item.content} className="w-12 h-12 object-cover rounded" alt="thumb" />
                                                ) : (
                                                    <div className="w-12 h-12 flex items-center justify-center bg-gray-700 rounded text-xs text-white">FILE</div>
                                                )}
                                            </div>
                                        )}
                                        <div className="text-xs text-center truncate w-full mt-2" title={item.name}>{item.name}</div>
                                        <div className="text-[10px] text-green-700 mt-1">{formatSize(item.size)}</div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Details / Actions Pane */}
                    {selectedItem && (
                        <div className="w-64 border-l border-green-500/30 p-4 bg-black/20 flex flex-col">
                            <h3 className="text-lg font-bold truncate mb-4 border-b border-green-500/30 pb-2">{selectedItem.name}</h3>
                            <div className="space-y-4 flex-1">
                                <div className="text-sm">
                                    <span className="text-green-700 block text-xs uppercase">Type</span>
                                    {selectedItem.type}
                                </div>
                                <div className="text-sm">
                                    <span className="text-green-700 block text-xs uppercase">Size</span>
                                    {formatSize(selectedItem.size)}
                                </div>
                                <div className="text-sm">
                                    <span className="text-green-700 block text-xs uppercase">Created</span>
                                    {new Date(selectedItem.createdAt).toLocaleDateString()}
                                </div>
                            </div>
                            <div className="mt-4 space-y-2">
                                {selectedItem.type === 'file' && (
                                    <>
                                        <button onClick={() => downloadFile(selectedItem)} className="w-full py-2 bg-green-700 hover:bg-green-600 text-white rounded text-sm flex items-center justify-center space-x-2">
                                            <DownloadIcon className="w-4 h-4"/> <span>Download</span>
                                        </button>
                                        <button onClick={() => setShowShareModal(true)} className="w-full py-2 bg-blue-900/50 border border-blue-500 hover:bg-blue-800/50 text-blue-300 rounded text-sm flex items-center justify-center space-x-2">
                                            <LockOpenIcon className="w-4 h-4"/> <span>Secure Share</span>
                                        </button>
                                    </>
                                )}
                                <button onClick={() => handleDelete(selectedItem.id)} className="w-full py-2 bg-red-900/50 border border-red-500 hover:bg-red-800/50 text-red-300 rounded text-sm flex items-center justify-center space-x-2">
                                    <TrashIcon className="w-4 h-4"/> <span>Delete</span>
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Share Modal */}
            {showShareModal && (
                <div className="absolute inset-0 z-[60] flex items-center justify-center bg-black/80">
                    <div className="bg-gray-800 border border-blue-500 rounded p-6 w-96 text-blue-300">
                        <h3 className="text-lg font-bold mb-4 flex items-center"><LockIcon className="w-5 h-5 mr-2"/> Secure Share</h3>
                        <p className="text-xs mb-4 text-blue-400">
                            Create a password-protected <code>.nexusvault</code> file. You must share the password with the recipient separately.
                        </p>
                        <input 
                            type="password" 
                            placeholder="Set Encryption Password" 
                            className="w-full bg-gray-900 border border-blue-500/50 rounded p-2 mb-4 text-white focus:outline-none focus:border-blue-500"
                            value={sharePassword}
                            onChange={(e) => setSharePassword(e.target.value)}
                        />
                        <div className="flex justify-end space-x-2">
                            <button onClick={() => setShowShareModal(false)} className="px-4 py-2 hover:bg-gray-700 rounded">Cancel</button>
                            <button onClick={handleSecureShare} disabled={!sharePassword} className="px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded disabled:opacity-50">Generate</button>
                        </div>
                    </div>
                </div>
            )}

            {/* Import Modal */}
            {showImportModal && (
                <div className="absolute inset-0 z-[60] flex items-center justify-center bg-black/80">
                    <div className="bg-gray-800 border border-green-500 rounded p-6 w-96 text-green-300">
                        <h3 className="text-lg font-bold mb-4 flex items-center"><DownloadIcon className="w-5 h-5 mr-2"/> Import Secure Package</h3>
                        <p className="text-xs mb-4 text-green-400">
                            Enter the password provided by the sender to decrypt the file into your "Not Mine" folder.
                        </p>
                        <input 
                            type="password" 
                            placeholder="Decryption Password" 
                            className="w-full bg-gray-900 border border-green-500/50 rounded p-2 mb-4 text-white focus:outline-none focus:border-green-500"
                            value={importPassword}
                            onChange={(e) => setImportPassword(e.target.value)}
                        />
                        <div className="flex space-x-2">
                            <input 
                                type="file" 
                                ref={secureImportInputRef} 
                                accept=".nexusvault" 
                                onChange={handleSecureImport}
                                className="hidden"
                            />
                            <button onClick={() => setShowImportModal(false)} className="px-4 py-2 hover:bg-gray-700 rounded">Cancel</button>
                            <button onClick={() => secureImportInputRef.current?.click()} disabled={!importPassword} className="flex-1 px-4 py-2 bg-green-600 hover:bg-green-500 text-white rounded disabled:opacity-50 text-center">Select File</button>
                        </div>
                    </div>
                </div>
            )}

            {inputModal && (
                <InputModal 
                    title={inputModal.title}
                    label={inputModal.label}
                    onConfirm={inputModal.onConfirm}
                    onCancel={() => setInputModal(null)}
                />
            )}
        </div>
    );
};
